package github.chains;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class Main {
    public static void main(String[] args) throws IOException {
        String pomPath = "/workspace/liquibase-mssql/pom.xml";
        String content = Files.readString(Paths.get(pomPath));

        Pattern sourcePattern = Pattern.compile("<source>1\\.6</source>");
        Pattern targetPattern = Pattern.compile("<target>1\\.6</target>");

        String modified = sourcePattern.matcher(content).replaceAll("<source>1.7</source>");
        modified = targetPattern.matcher(modified).replaceAll("<target>1.7</target>");

        Files.writeString(Paths.get(pomPath), modified);
        System.out.println("Fixed pom.xml: changed source/target from 1.6 to 1.7");
    }
}

